#nullable enable // autogenerated

using UnityEngine;
using UnityEngine.UI;

namespace MVZ2.Talk
{
    public class CharacterPortraitComponentLayer : MonoBehaviour
    {
        public void UpdateLayer(CharacterPortraitLayerViewData viewData)
        {
            image.sprite = viewData.sprite;
            image.enabled = image.sprite;
            rectTransform.anchoredPosition = viewData.position;
            rectTransform.sizeDelta = image.sprite.Exists() ? image.sprite.rect.size : Vector2.zero;
        }
        public RectTransform rectTransform = null!;
        public Image image = null!;
    }
    public struct CharacterPortraitLayerViewData
    {
        public Vector2 position;
        public Vector2 size;
        public Sprite? sprite;
    }
}
